const BASE_URL = 'https://news-d.vercel.app';
const BUSINESS = '923439798418@c.us';
const LIMIT = 2;

const ALLOWED = new Set([
  '923138308265@c.us',
  '193277873631353@lid',
]);

const root = $input.first()?.json || {};
const body = root.body || root;
const event = String(body.event || root.event || '');
const payload = body.payload || root.payload || body;

if (event && event !== 'message') return [];
if (!payload || typeof payload !== 'object') return [];
if (payload.fromMe) return [];

const from = String(payload.from || '').trim();
if (!from || from === BUSINESS) return [];

if (ALLOWED.size > 0 && !ALLOWED.has(from)) {
  const digits = from.replace(/\\D/g, '');
  const ok = [...ALLOWED].some((a) => {
    const ad = a.replace(/\\D/g, '');
    return ad && digits && (digits.includes(ad) || ad.includes(digits));
  });
  if (!ok) return [];
}

const text = String(payload.body || payload.caption || '').trim();
const media = payload.media || payload._data?.media || null;
const mime = String(
  (media && (media.mimetype || media.mime_type || media.mimeType)) ||
  payload.mimetype ||
  payload._data?.mimetype ||
  ''
).toLowerCase();
const msgType = String(payload.type || payload._data?.type || payload.message?.type || '').toLowerCase();
const hasMedia = Boolean(payload.hasMedia || media?.url || media?.link);
const isVoice =
  msgType === 'ptt' ||
  msgType === 'audio' ||
  msgType === 'voice' ||
  mime.startsWith('audio/') ||
  /\\b(ptt|audio|ogg|opus)\\b/i.test(mime);

let mediaUrl = '';
if (isVoice && hasMedia) {
  mediaUrl = String(
    media?.url ||
    media?.link ||
    media?.path ||
    payload.mediaUrl ||
    payload._data?.deprecatedMms3Url ||
    ''
  ).trim();
  // Rewrite localhost or relative paths → Docker service hostname
  if (mediaUrl && mediaUrl.startsWith('/')) {
    mediaUrl = 'http://waha:3000' + mediaUrl;
  } else if (mediaUrl && /^https?:\/\/(localhost|127\.0\.0\.1)(:\d+)?/i.test(mediaUrl)) {
    mediaUrl = mediaUrl.replace(/^https?:\/\/(localhost|127\.0\.0\.1)(:\d+)?/i, 'http://waha:3000');
  }
}

if (!text && !mediaUrl) return [];
if (text && (text.startsWith('NewsDash') || text.startsWith('*NewsDash'))) return [];

const msgId = typeof payload.id === 'string'
  ? payload.id
  : String((payload.id && (payload.id._serialized || payload.id.id)) || (payload.timestamp + ':' + (text || mediaUrl).slice(0, 40)));

try {
  const staticData = $getWorkflowStaticData('global');
  if (!staticData.seen) staticData.seen = {};
  if (staticData.seen[msgId]) return [];
  staticData.seen[msgId] = Date.now();
  const cutoff = Date.now() - 6 * 60 * 60 * 1000;
  for (const k of Object.keys(staticData.seen)) {
    if (staticData.seen[k] < cutoff) delete staticData.seen[k];
  }
} catch (e) {}

return [{
  json: {
    q: text,
    mediaUrl,
    mimeType: mime || (mediaUrl ? 'audio/ogg' : ''),
    needsTranscribe: Boolean(mediaUrl && !text),
    chatId: from,
    baseUrl: BASE_URL,
    limit: LIMIT,
    messageId: msgId,
  },
}];

const item = $input.first()?.json || {};
let q = String(item.q || '').trim();
const chatId = String(item.chatId || '');
const baseUrl = String(item.baseUrl || 'https://news-d.vercel.app');
const limit = item.limit || 2;
const mediaUrl = String(item.mediaUrl || '').trim();
const mimeType = String(item.mimeType || 'audio/ogg').split(';')[0].trim() || 'audio/ogg';

const failHear = () => ([{
  json: {
    chatId,
    baseUrl,
    limit,
    q: '',
    skipQuery: true,
    whatsappText: '*NewsDash Analyst*\n\nCould not hear that - please retry or type your question.',
  },
}]);

if ((!q || item.needsTranscribe) && mediaUrl) {
  try {
    const audio = await this.helpers.httpRequest({
      method: 'GET',
      url: mediaUrl,
      encoding: 'arraybuffer',
      returnFullResponse: false,
      json: false,
      timeout: 30000,
    });
    const buf = Buffer.isBuffer(audio)
      ? audio
      : Buffer.from(audio?.data || audio || []);
    if (!buf.length) return failHear();

    const ext = mimeType.includes('mpeg') || mimeType.includes('mp3')
      ? 'mp3'
      : mimeType.includes('mp4') || mimeType.includes('m4a')
        ? 'm4a'
        : mimeType.includes('wav')
          ? 'wav'
          : 'ogg';

    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: baseUrl + '/api/transcribe',
      headers: {},
      formData: {
        file: {
          value: buf,
          options: { filename: 'voice.' + ext, contentType: mimeType },
        },
      },
      json: true,
      timeout: 60000,
    });
    q = String(resp?.text || '').trim();
    if (!q) return failHear();
  } catch (e) {
    return failHear();
  }
}

if (!q || q.length < 2) {
  return [{
    json: {
      chatId,
      baseUrl,
      limit,
      q: '',
      skipQuery: true,
      whatsappText: '*NewsDash Analyst*\n\nPlease send a short text or voice question.',
    },
  }];
}

return [{ json: { q, chatId, baseUrl, limit, skipQuery: false } }];

const item = $input.first()?.json || {};
const chatId = String(item.chatId || '');

const staticData = $getWorkflowStaticData('global');
if (!staticData.history) staticData.history = {};
if (!staticData.topicContext) staticData.topicContext = {};

const history = staticData.history[chatId] || [];
const lastTopic = staticData.topicContext[chatId] || '';

return [{ json: { ...item, history, lastTopic } }];

const item = $input.first()?.json || {};
const q = String(item.q || '').trim();
const lastTopic = String(item.lastTopic || '').trim();
const skipQuery = Boolean(item.skipQuery);

if (skipQuery) {
  return [{ json: { ...item, effectiveQuery: '', isFollowUp: false } }];
}

// Detect Urdu + English follow-up / continuation phrases
const FOLLOWUP_RE = /^(\s*(\u0627\u0648\u0631|\u0645\u0632\u06CC\u062F|\u0622\u06AF\u06D2|\u0628\u062A\u0627\u0624|\u0628\u062A\u0627\u0626\u06CC\u06BA|\u0627\u06AF\u0644\u0627|\u0627\u06AF\u0644\u06CC|\u067E\u06BE\u0631|\u06C1\u0627\u06BA|okay|ok|more|next|go on|continue|and then|tell me more|what else|anything else|elaborate|details?|explain more|haan|theek hai|aur|mazeed|agay|batao|batain|phir|aur batao|aur kuch|kuch aur|show more|related|\u0645\u062A\u0639\u0644\u0642|\u0645\u0632\u06CC\u062F \u062E\u0628\u0631\u06CC\u06BA|\u0645\u0632\u06CC\u062F \u0628\u062A\u0627\u0626\u06CC\u06BA|\u0627\u0633 \u06A9\u06D2 \u0628\u0627\u0631\u06D2 \u0645\u06CC\u06BA|\u0627\u0633 \u0628\u0627\u0631\u06D2 \u0645\u06CC\u06BA)\s*[?!]*\s*)$/i;

const isUrduOnly = /^[\u0600-\u06FF\s?!.,]+$/.test(q);
const isFollowUp = q.length < 50 && (FOLLOWUP_RE.test(q) || (q.length < 20 && lastTopic && isUrduOnly));

const effectiveQuery = isFollowUp && lastTopic ? lastTopic : q;
const extraLimit = isFollowUp ? 2 : 0;

return [{ json: { ...item, effectiveQuery, isFollowUp, extraLimit } }];

