={{ (function() {
  const resolved  = $('Resolve Text Query').first().json || {};
  const loaded    = $('Load Chat History').first().json || {};
  const topicNode = $('Resolve Query Topic').first().json || {};
  const history   = Array.isArray(loaded.history) ? loaded.history : [];
  const isFollowUp  = Boolean(topicNode.isFollowUp);
  const lastTopic   = String(topicNode.lastTopic || '');

  let newsContext = '';
  try {
    const qResp = $('Query NewsDash').first()?.json;
    const items = qResp?.items || qResp?.results || [];
    if (Array.isArray(items) && items.length) {
      newsContext = items.slice(0, 5).map((i, n) =>
        (n+1) + '. ' + (i.title || '') + ' [' + (i.source || '') + '] -- ' + (i.description || '').slice(0, 120)
      ).join('\n');
    } else if (typeof qResp?.whatsappText === 'string') {
      newsContext = qResp.whatsappText.slice(0, 1000);
    }
  } catch(e) {}

  if (isFollowUp && !newsContext && lastTopic) {
    const lastAssistant = [...history].reverse().find(function(m) { return m.role === 'assistant'; });
    if (lastAssistant) {
      newsContext = '(Continuing previous discussion about: ' + lastTopic + ')';
    }
  }

  let effectiveQ = String(resolved.q || '');
  if (isFollowUp && lastTopic) {
    effectiveQ = '[Follow-up about: ' + lastTopic + '] ' + effectiveQ;
  }

  return JSON.stringify({
    q: effectiveQ,
    history: history.slice(-40),
    newsContext: newsContext,
  });
})() }}

