const resolved  = $('Resolve Text Query').first().json || {};
const topicNode = $('Resolve Query Topic').first().json || {};
const chatId    = String(resolved.chatId || '');
const q         = String(resolved.q || '');

if (resolved.skipQuery && resolved.whatsappText) {
  return [{ json: { chatId, text: String(resolved.whatsappText) } }];
}

let replyText = '';
try {
  const chatResp = $('Call Groq Chat API').first()?.json;
  replyText = String(chatResp?.text || '').trim();
} catch (e) {}

if (!replyText) {
  try {
    const newsResp = $('Query NewsDash').first()?.json;
    replyText = String(newsResp?.whatsappText || '').trim();
  } catch(e) {}
}

if (!replyText) {
  replyText = '*NewsDash Analyst*\n\nSorry, could not get a response right now. Please try again.';
}

try {
  const staticData = $getWorkflowStaticData('global');
  if (!staticData.history)      staticData.history      = {};
  if (!staticData.topicContext) staticData.topicContext = {};

  const hist = staticData.history[chatId] || [];
  hist.push({ role: 'user',      content: q });
  hist.push({ role: 'assistant', content: replyText });
  staticData.history[chatId] = hist.slice(-40);

  const isFollowUp     = Boolean(topicNode.isFollowUp);
  const effectiveQuery = String(topicNode.effectiveQuery || q);
  if (!isFollowUp && effectiveQuery.length > 3) {
    staticData.topicContext[chatId] = effectiveQuery;
  }
} catch (e) {}

return [{ json: { chatId, text: replyText } }];
